#!/bin/bash
echo "=== Exporting troubleshoot_split_study task result ==="

source /workspace/scripts/task_utils.sh

# Record end time & extract start time
TASK_END=$(date +%s)
TASK_START=$(cat /tmp/task_start_time.txt 2>/dev/null || echo "0")

take_screenshot /tmp/task_final.png

REPORT_PATH="/home/ga/DICOM/exports/mismatch_report.txt"
REPORT_EXISTS="false"
REPORT_CONTENT=""
FILE_CREATED_DURING_TASK="false"

# Check the report file generated by the agent
if [ -f "$REPORT_PATH" ]; then
    REPORT_EXISTS="true"
    # Safely extract up to 10 lines of text, removing carriage returns, escaping quotes, and converting newlines to pipes
    REPORT_CONTENT=$(cat "$REPORT_PATH" | head -n 10 | tr -d '\r' | sed 's/"/\\"/g' | tr '\n' '|')
    
    # Check modification time against task start (anti-gaming check)
    OUTPUT_MTIME=$(stat -c %Y "$REPORT_PATH" 2>/dev/null || echo "0")
    if [ "$OUTPUT_MTIME" -gt "$TASK_START" ]; then
        FILE_CREATED_DURING_TASK="true"
    fi
fi

# Read hidden ground truth generated during setup
GT_FILE="/var/lib/app/ground_truth/qa_answer.json"
EXPECTED_FILENAME=""
EXPECTED_PATIENT_ID=""

if [ -f "$GT_FILE" ]; then
    EXPECTED_FILENAME=$(python3 -c "import json; print(json.load(open('$GT_FILE')).get('corrupted_filename', ''))" 2>/dev/null)
    EXPECTED_PATIENT_ID=$(python3 -c "import json; print(json.load(open('$GT_FILE')).get('mismatched_patient_id', ''))" 2>/dev/null)
fi

APP_RUNNING=$(pgrep -f "weasis" > /dev/null && echo "true" || echo "false")

# Assemble the JSON export using a safe temporary file technique
TEMP_JSON=$(mktemp /tmp/result.XXXXXX.json)
cat > "$TEMP_JSON" << EOF
{
    "task_start": $TASK_START,
    "task_end": $TASK_END,
    "report_exists": $REPORT_EXISTS,
    "file_created_during_task": $FILE_CREATED_DURING_TASK,
    "report_content": "$REPORT_CONTENT",
    "expected_filename": "$EXPECTED_FILENAME",
    "expected_patient_id": "$EXPECTED_PATIENT_ID",
    "app_was_running": $APP_RUNNING,
    "timestamp": "$(date -Iseconds)"
}
EOF

# Ensure global read/write access to the output JSON so it can be picked up safely
rm -f /tmp/task_result.json 2>/dev/null || sudo rm -f /tmp/task_result.json 2>/dev/null || true
cp "$TEMP_JSON" /tmp/task_result.json 2>/dev/null || sudo cp "$TEMP_JSON" /tmp/task_result.json
chmod 666 /tmp/task_result.json 2>/dev/null || sudo chmod 666 /tmp/task_result.json 2>/dev/null || true
rm -f "$TEMP_JSON"

echo "Result saved to /tmp/task_result.json"
cat /tmp/task_result.json
echo "=== Export complete ==="